    var parms = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
    Console.WriteLine($"{m.Name}{genArgs}({parms})");
}
"""
with open("/tmp/check_assert.csx", "w") as f:
    f.write(script)
result = subprocess.run(["dotnet", "script", "/tmp/check_assert.csx"], capture_output=True, text=True)
print(result.stdout)
print(result.stderr)
EOF

